class Solution:
    def maxDistinctElements(self, nums, k):
        n = len(nums)
        order = sorted(range(n), key=lambda i: nums[i])
        used = set()
        count = 0
        for i in order:
            lo = nums[i] - k
            hi = nums[i] + k
            v = lo
            while v in used and v <= hi:
                v += 1
            if v <= hi:
                used.add(v)
                count += 1
        return count

