class Solution:
    def maxDistinctElements(self, nums, k):
        nums = sorted(nums)
        last = float('-inf')
        count = 0
        for num in nums:
            lo = num - k
            hi = num + k
            candidate = lo if last == float('-inf') else max(lo, last + 1)
            if candidate <= hi:
                count += 1
                last = candidate
        return count

