var maxDistinctElements = function(nums, k) {
    const sorted = nums.slice().sort((a, b) => a - b);
    let last = null;
    let count = 0;
    for (const num of sorted) {
        const lo = num - k;
        const hi = num + k;
        const candidate = last === null ? lo : Math.max(lo, last + 1);
        if (candidate <= hi) {
            count += 1;
            last = candidate;
        }
    }
    return count;
};
